from fastapi import FastAPI; from fastapi.middleware.cors import CORSMiddleware; app = FastAPI(); app.add_middleware(CORSMiddleware, allow_origins=['http://localhost:5173'], allow_origin_regex=r'^https?://(localhost(:\d+)?|192\.168\.\d+\.\d+(:\d+)?|.*\.ngrok-free\.app|.*\.ngrok\.io)$'); from starlette.testclient import TestClient; client = TestClient(app); print(client.options('/', headers={'Origin': 'http://192.168.1.12:5174', 'Access-Control-Request-Method': 'GET'}).status_code)
